        forever begin
            @(posedge vif.clk);

            // 检测有效事务
            if (vif.valid && vif.ready) begin
                my_transaction tr = new();

                // 采集数据
                tr.addr = vif.addr;
                tr.data = vif.we ? vif.wdata : vif.rdata;
                tr.kind = vif.we ? WRITE : READ;

                `uvm_info("MONITOR", $sformatf("Sampled: %s", tr.convert2string()), UVM_HIGH)

                // 发送事务
                ap.write(tr);
            end
        end
    endtask
endclass
```

